code.base_class:
/* Classe reutilizável — aplicar em qualquer elemento com position:relative */
.liquid-glass {
  background: rgba(255, 255, 255, 0.01);
  background-blend-mode: luminosity;
  backdrop-filter: blur(4px);
  -webkit-backdrop-filter: blur(4px);
  border: none;  /* borda é feita via ::before */
  box-shadow: inset 0 1px 1px rgba(255, 255, 255, 0.1);
  position: relative;
  overflow: hidden;
}

code.gradient_border:
/* Borda gradiente — técnica mask-composite */
.liquid-glass::before {
  content: '';
  position: absolute;
  inset: 0;
  border-radius: inherit;  /* herda border-radius do elemento pai */
  padding: 1.4px;          /* espessura da borda */
  background: linear-gradient(
    180deg,
    rgba(255,255,255,0.45) 0%,
    rgba(255,255,255,0.15) 20%,
    rgba(255,255,255,0)    40%,
    rgba(255,255,255,0)    60%,
    rgba(255,255,255,0.15) 80%,
    rgba(255,255,255,0.45) 100%
  );
  /* Máscara que exclui o interior — sobra apenas o padding = borda */
  -webkit-mask:
    linear-gradient(#fff 0 0) content-box,
    linear-gradient(#fff 0 0);
  -webkit-mask-composite: xor;
  mask-composite: exclude;
  pointer-events: none;
}

code.variations:
/* Variação: borda mais fina e sutil */
.liquid-glass-subtle::before { padding: 0.8px; }

/* Variação: blur mais forte para overlays */
.liquid-glass-heavy {
  backdrop-filter: blur(12px);
  background: rgba(255,255,255,0.05);
}

/* Variação: tint colorido para contexto de cor */
.liquid-glass-tinted {
  background: rgba(115, 66, 226, 0.08); /* tint roxo */
  backdrop-filter: blur(8px);
}

